const https = require('https');
const urlMod = require('url');
function httpReq(method, rawUrl, headers, postBody) {
  return new Promise((resolve, reject) => {
    const parsed = urlMod.parse(rawUrl);
    const opts = { hostname: parsed.hostname, path: parsed.path, method: method, headers: headers || {} };
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        let json = null;
        try { json = JSON.parse(body); } catch(e) {}
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, json: json, text: body });
      });
    });
    req.on('error', reject);
    if (postBody) req.write(typeof postBody === 'string' ? postBody : JSON.stringify(postBody));
    req.end();
  });
}

// Labor Cap Monitor: checks if crew payout exceeds labor budget
const GHL_TOKEN = '{{ghl_token}}';
const LOCATION_ID = '{{ghl_location_id}}';
const LABOR_BUDGET_FIELD = '{{ghl_cf_labor_budget}}';
const CREW_PAYOUT_FIELD = '{{ghl_cf_crew_payout}}';
const LABOR_CAP_PCT = {{labor_cap_pct}};
const BASE = 'https://services.leadconnectorhq.com';
const HEADERS = { 'Authorization': `Bearer ${GHL_TOKEN}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' };

const body = $input.first().json;
const oppId = body.opportunity_id || body.id;
if (!oppId) return [{ json: { status: 'error', message: 'No opportunity ID' } }];

const resp = await httpReq('GET', `${BASE}/opportunities/${oppId}`, HEADERS );
const opp = await resp.json;

const fields = opp.customFields || [];
const laborBudget = parseFloat((fields.find(f => f.id === LABOR_BUDGET_FIELD))?.value) || 0;
const crewPayout = parseFloat((fields.find(f => f.id === CREW_PAYOUT_FIELD))?.value) || 0;
const contractValue = parseFloat(opp.monetaryValue) || 0;
const laborPct = contractValue > 0 ? (crewPayout / contractValue * 100) : 0;

if (laborPct > LABOR_CAP_PCT) {
  return [{ json: { status: 'flagged', opportunity_id: oppId, name: opp.name, labor_pct: laborPct.toFixed(1), cap: LABOR_CAP_PCT, crew_payout: crewPayout, contract_value: contractValue, message: `Labor at ${laborPct.toFixed(1)}% exceeds ${LABOR_CAP_PCT}% cap` } }];
}
if (crewPayout > laborBudget && laborBudget > 0) {
  return [{ json: { status: 'over_budget', opportunity_id: oppId, name: opp.name, crew_payout: crewPayout, labor_budget: laborBudget, overage: crewPayout - laborBudget } }];
}
return [{ json: { status: 'ok', opportunity_id: oppId, labor_pct: laborPct.toFixed(1) } }];
